import{_ as a,o as t,c as n,a2 as o}from"./chunks/framework.CHSDihme.js";const u=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1780340868000}'),i={name:"guide/faq.md"};function s(p,e,d,r,c,l){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="q-undefined-is-not-an-object-evaluating-usageinput_tokens" tabindex="-1">Q: <code>undefined is not an object (evaluating &#39;usage.input_tokens&#39;)</code> <a class="header-anchor" href="#q-undefined-is-not-an-object-evaluating-usageinput_tokens" aria-label="Permalink to &quot;Q: `undefined is not an object (evaluating &#39;usage.input_tokens&#39;)`&quot;">​</a></h2><p><strong>原因</strong>：<code>ANTHROPIC_BASE_URL</code> 配置不正确，API 端点返回的不是 Anthropic 协议格式的 JSON，而是 HTML 页面或其他格式。</p><p>本项目使用 <strong>Anthropic Messages API 协议</strong>，<code>ANTHROPIC_BASE_URL</code> 必须指向一个兼容 Anthropic <code>/v1/messages</code> 接口的端点。Anthropic SDK 会自动在 base URL 后面拼接 <code>/v1/messages</code>，所以：</p><ul><li>MiniMax：<code>ANTHROPIC_BASE_URL=https://api.minimaxi.com/anthropic</code> ✅</li><li>OpenRouter：<code>ANTHROPIC_BASE_URL=https://openrouter.ai/api</code> ✅</li><li>OpenRouter 错误写法：<code>ANTHROPIC_BASE_URL=https://openrouter.ai/anthropic</code> ❌（返回 HTML）</li></ul><p>如果你的模型供应商只支持 OpenAI 协议，需要通过 LiteLLM 等代理做协议转换，详见 <a href="./third-party-models.html">第三方模型使用指南</a>。</p><h2 id="q-cannot-find-package-bundle" tabindex="-1">Q: <code>Cannot find package &#39;bundle&#39;</code> <a class="header-anchor" href="#q-cannot-find-package-bundle" aria-label="Permalink to &quot;Q: `Cannot find package &#39;bundle&#39;`&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>error: Cannot find package &#39;bundle&#39; from &#39;.../claude-code-haha/src/entrypoints/cli.tsx&#39;</span></span></code></pre></div><p><strong>原因</strong>：Bun 版本过低，不支持项目所需的 <code>bun:bundle</code> 等内置模块。</p><p><strong>解决</strong>：升级 Bun 到最新版本：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bun</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> upgrade</span></span></code></pre></div><h2 id="q-怎么接入-openai--deepseek--ollama-等非-anthropic-模型" tabindex="-1">Q: 怎么接入 OpenAI / DeepSeek / Ollama 等非 Anthropic 模型？ <a class="header-anchor" href="#q-怎么接入-openai--deepseek--ollama-等非-anthropic-模型" aria-label="Permalink to &quot;Q: 怎么接入 OpenAI / DeepSeek / Ollama 等非 Anthropic 模型？&quot;">​</a></h2><p>本项目只支持 Anthropic 协议。如果模型供应商不直接支持 Anthropic 协议，需要用 <a href="https://github.com/BerriAI/litellm" target="_blank" rel="noreferrer">LiteLLM</a> 等代理做协议转换（OpenAI → Anthropic）。</p><p>详细配置步骤请参考：<a href="./third-party-models.html">第三方模型使用指南</a></p>',14)])])}const g=a(i,[["render",s]]);export{u as __pageData,g as default};
